import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as a,d as e}from"./app-3c21af73.js";const l={},t=e(`<h1 id="ansible变量" tabindex="-1"><a class="header-anchor" href="#ansible变量" aria-hidden="true">#</a> Ansible变量</h1><p>我们来说明ansible中变量（不包含role中的变量）用法。</p><h2 id="命令行变量" tabindex="-1"><a class="header-anchor" href="#命令行变量" aria-hidden="true">#</a> 命令行变量</h2><p>在 Ansible 中，我们可以使用 external variables（外部变量）来引入外部定义的变量。通常情况下，我们会将变量定义在 playbook 文件中或者 inventory 文件中，但是如果我们需要在 playbook 执行时动态地传入一些参数或者配置文件中包含了一些需要使用的变量，我们就可以使用 ext_vars 来引入这些变量。</p><p>在执行 ansible-playbook 命令时，我们可以使用 <code>-e</code> 或者 <code>--extra-vars</code> 参数来指定外部变量文件，也可以直接在命令行中使用 <code>key=value</code> 的形式指定变量。举个例子，假设我们有一个 playbook 文件，需要使用一个外部变量 <code>user</code> 来指定要部署的应用程序的用户，我们可以在命令行中这样使用：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ansible-playbook myplaybook.yml <span class="token parameter variable">-e</span> <span class="token string">&quot;user=myappuser&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样在 playbook 中就可以使用 <code>{{ user }}</code> 来引用这个外部变量了，例如：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token comment"># myplaybook.yml</span>
<span class="token punctuation">---</span>
 <span class="token punctuation">-</span> <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
   <span class="token key atrule">gather_facts</span><span class="token punctuation">:</span> no
   <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
     <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> test external variables
       <span class="token key atrule">command</span><span class="token punctuation">:</span> echo <span class="token punctuation">{</span><span class="token punctuation">{</span> user <span class="token punctuation">}</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>我们也可以将变量定义在一个 YAML 格式的文件中，然后通过 <code>-e</code> 参数指定这个文件，例如：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token comment"># vars.yml</span>
<span class="token key atrule">user</span><span class="token punctuation">:</span> myappuser
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ansible-playbook myplaybook.yml <span class="token parameter variable">-e</span> <span class="token string">&quot;@vars.yml&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样 playbook 中就可以使用 <code>{{ user }}</code> 来引用这个外部变量了。</p><blockquote><p><strong>注意</strong>:当我们在 playbook 中定义了一个变量，而且同时又使用 <code>-e</code> 参数指定了同名的外部变量时，外部变量的值会覆盖 playbook 中的变量值。</p></blockquote><h2 id="inventory变量" tabindex="-1"><a class="header-anchor" href="#inventory变量" aria-hidden="true">#</a> inventory变量</h2><p>在 Ansible 的 inventory 中，可以定义主机变量、组变量和子组变量。这些变量可以在 playbook 中使用，来实现对主机或主机组的定制化配置。</p><p>以以下 inventory 为例：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">web_servers</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">web1 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">192.168.1.1</span>
<span class="token key attr-name">web2 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">192.168.1.2</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">db_servers</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">db1 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">192.168.1.3</span>
<span class="token key attr-name">db2 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">192.168.1.4</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">prod_servers:children</span><span class="token punctuation">]</span></span>
web_servers
db_servers

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">web_servers:vars</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">http_port</span><span class="token punctuation">=</span><span class="token value attr-value">8080</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">db_servers:vars</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">db_port</span><span class="token punctuation">=</span><span class="token value attr-value">3306</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">prod_servers:vars</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">app_env</span><span class="token punctuation">=</span><span class="token value attr-value">production</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这个 inventory 中，我们定义了四个主机：<code>web1</code>、<code>web2</code>、<code>db1</code>、<code>db2</code>，并将它们分别归属到了两个组：<code>web_servers</code>、<code>db_servers</code>。此外，我们还定义了一个父组 <code>prod_servers</code>，它包含了 <code>web_servers</code> 和 <code>db_servers</code> 两个子组。在 <code>web_servers</code> 和 <code>db_servers</code> 组内，分别定义了变量 <code>http_port</code> 和 <code>db_port</code>。在 <code>prod_servers</code> 组内，定义了变量 <code>app_env</code>。</p><p>接下来，我们编写一个 playbook，来应用这些变量。</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">---</span>
<span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Start HTTP service
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> web_servers
  <span class="token key atrule">become</span><span class="token punctuation">:</span> yes
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Ensure HTTP service is running
      <span class="token key atrule">service</span><span class="token punctuation">:</span>
        <span class="token key atrule">name</span><span class="token punctuation">:</span> httpd
        <span class="token key atrule">state</span><span class="token punctuation">:</span> started
        <span class="token key atrule">enabled</span><span class="token punctuation">:</span> yes
      <span class="token key atrule">when</span><span class="token punctuation">:</span> <span class="token string">&quot;http_port is defined&quot;</span>
        
<span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Start MySQL service
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> db_servers
  <span class="token key atrule">become</span><span class="token punctuation">:</span> yes

  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Ensure MySQL service is running
      <span class="token key atrule">service</span><span class="token punctuation">:</span>
        <span class="token key atrule">name</span><span class="token punctuation">:</span> mysqld
        <span class="token key atrule">state</span><span class="token punctuation">:</span> started
        <span class="token key atrule">enabled</span><span class="token punctuation">:</span> yes
      <span class="token key atrule">when</span><span class="token punctuation">:</span> <span class="token string">&quot;db_port is defined&quot;</span>

<span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Update app conf
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> prod_servers
  <span class="token key atrule">become</span><span class="token punctuation">:</span> yes
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Copy app config file
      <span class="token key atrule">template</span><span class="token punctuation">:</span>
        <span class="token key atrule">src</span><span class="token punctuation">:</span> app.conf.j2
        <span class="token key atrule">dest</span><span class="token punctuation">:</span> /etc/app.conf
      <span class="token key atrule">when</span><span class="token punctuation">:</span> app_env == &#39;production&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这个 playbook 中，我们定义了一个playbook，它针对 <code>prod_servers</code> 主机组中的所有主机执行任务。这个 playbook 的任务有三个：</p><ul><li>确保 HTTP 服务运行。在执行这个任务之前，我们先判断主机的变量 <code>http_port</code> 是否被定义了。如果不存在或未定义，这个任务将被忽略。</li><li>确保 MySQL 服务运行。和上一个任务类似，这个任务会判断主机的变量 <code>db_port</code> 是否被定义了。如果不存在或未定义，这个任务将被忽略。</li><li>复制应用程序的配置文件。在执行这个任务之前，我们先判断变量 <code>app_env</code> 是否等于 <code>production</code>。如果不等于，这个任务将被忽略。</li></ul><p>通过这个 playbook，我们可以根据不同的变量配置，为不同的主机或主机组定制化地执行任务。</p><h2 id="playbook变量" tabindex="-1"><a class="header-anchor" href="#playbook变量" aria-hidden="true">#</a> playbook变量</h2><p>Playbook变量是在playbook级别上定义的变量，它们在playbook中的所有任务和角色中都可用。这些变量可以用于配置任务、定义主机和组、指定条件等。</p><p>下面是一个使用playbook变量的例子：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">---</span>
<span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Playbook with variables
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
  <span class="token key atrule">vars</span><span class="token punctuation">:</span>
    <span class="token key atrule">web_server_port</span><span class="token punctuation">:</span> <span class="token number">80</span>
    <span class="token key atrule">db_server_port</span><span class="token punctuation">:</span> <span class="token number">3306</span>
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Install Apache
      <span class="token key atrule">apt</span><span class="token punctuation">:</span>
        <span class="token key atrule">name</span><span class="token punctuation">:</span> apache2
        <span class="token key atrule">state</span><span class="token punctuation">:</span> present
      <span class="token key atrule">when</span><span class="token punctuation">:</span> <span class="token string">&quot;&#39;web&#39; in group_names&quot;</span>
      <span class="token key atrule">vars</span><span class="token punctuation">:</span>
        <span class="token key atrule">apache_listen_port</span><span class="token punctuation">:</span> <span class="token string">&quot;{{ web_server_port }}&quot;</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Install MySQL
      <span class="token key atrule">apt</span><span class="token punctuation">:</span>
        <span class="token key atrule">name</span><span class="token punctuation">:</span> mysql<span class="token punctuation">-</span>server
        <span class="token key atrule">state</span><span class="token punctuation">:</span> present
      <span class="token key atrule">when</span><span class="token punctuation">:</span> <span class="token string">&quot;&#39;db&#39; in group_names&quot;</span>
      <span class="token key atrule">vars</span><span class="token punctuation">:</span>
        <span class="token key atrule">mysql_listen_port</span><span class="token punctuation">:</span> <span class="token string">&quot;{{ db_server_port }}&quot;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这个例子中，定义了两个playbook变量：<code>web_server_port</code>和<code>db_server_port</code>。这些变量在playbook中的所有任务和角色中都可用。在任务”Install Apache”和“Install MySQL”中，使用了这些变量来设置Apache和MySQL的监听端口。</p><h2 id="文件变量" tabindex="-1"><a class="header-anchor" href="#文件变量" aria-hidden="true">#</a> 文件变量</h2><p><code>vars_files</code> 和 <code>include_vars</code> 都是 Ansible 中用来加载变量文件的机制，但是它们有一些区别：</p><ul><li><code>vars_files</code>：将变量从文件中加载到 playbook 的变量空间中，可以使用 <code>vars_files</code> 关键字来指定一个或多个 YAML 格式的文件，Ansible 会按照指定的顺序将文件中的变量合并到 playbook 的变量空间中，如果存在相同名称的变量，后面的变量会覆盖之前的变量。<code>vars_files</code> 通常用于将多个变量文件整合在一起。</li><li><code>include_vars</code>：将变量从文件中加载到变量空间中，并返回一个包含变量的字典，可以使用 <code>include_vars</code> 关键字来指定一个文件，Ansible 会将文件中的变量加载到一个新的变量空间中，并返回一个包含变量的字典，可以使用 <code>vars</code> 关键字来指定变量名，如果没有指定 <code>vars</code> 关键字，则会将文件中的所有变量加载到变量空间中。<code>include_vars</code> 通常用于将外部变量文件加载到 playbook 的变量空间中。</li></ul><p>下面是一个使用 <code>vars_files</code> 和 <code>include_vars</code> 的示例：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token comment"># playbook.yml</span>

<span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Load variables
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
  <span class="token key atrule">vars_files</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> vars/vars1.yml
    <span class="token punctuation">-</span> vars/vars2.yml
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Task 1
      <span class="token key atrule">debug</span><span class="token punctuation">:</span>
        <span class="token key atrule">var</span><span class="token punctuation">:</span> var1

    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Task 2
      <span class="token key atrule">include_vars</span><span class="token punctuation">:</span>
        <span class="token key atrule">file</span><span class="token punctuation">:</span> vars/vars3.yml
        <span class="token key atrule">name</span><span class="token punctuation">:</span> my_vars
      <span class="token key atrule">debug</span><span class="token punctuation">:</span>
        <span class="token key atrule">var</span><span class="token punctuation">:</span> my_vars

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这个示例中，<code>vars_files</code> 加载了 <code>vars1.yml</code> 和 <code>vars2.yml</code> 文件中的变量，如果变量名冲突，后面的变量会覆盖之前的变量。而 <code>include_vars</code> 加载了 <code>vars3.yml</code> 文件中的变量，并将这些变量存储在名为 <code>my_vars</code> 的字典中，可以在后续的任务中使用这个字典中的变量。</p><h2 id="roles变量" tabindex="-1"><a class="header-anchor" href="#roles变量" aria-hidden="true">#</a> Roles变量</h2><p>在Ansible的roles中，有两种类型的变量可以被使用：角色默认变量和角色全局变量。</p><ol><li>角色默认变量</li></ol><p>角色默认变量是在roles中定义的变量，用于在roles内部使用。它们的定义通常是在roles的<code>defaults/main.yml</code>文件中。</p><p>举例来说，如果我们有一个名为“web”的角色，并且希望定义一个默认变量“http_port”，则可以在<code>roles/web/defaults/main.yml</code>文件中添加如下定义：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">http_port</span><span class="token punctuation">:</span> <span class="token number">80</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在使用这个角色时，如果没有定义“http_port”变量，则会使用默认值80。</p><ol start="2"><li>角色全局变量</li></ol><p>角色全局变量是在roles外部定义的变量，用于传递参数给roles。这些变量可以在roles的vars文件中使用。</p><p>举例来说，如果我们有一个名为“web”的角色，并且希望定义一个全局变量“nginx_version”，则可以在一个名为“vars.yml”的文件中定义该变量：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">nginx_version</span><span class="token punctuation">:</span> 1.18.0
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在使用这个角色时，可以使用“vars_files”指令将变量文件引入到playbook中，如下所示：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code>yamlCopy code
<span class="token punctuation">-</span> <span class="token key atrule">hosts</span><span class="token punctuation">:</span> webservers
  <span class="token key atrule">vars_files</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> vars.yml
  <span class="token key atrule">roles</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> web
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这个playbook将引入<code>vars.yml</code>文件中定义的变量，并将它们传递给“web”角色。</p><blockquote><p><strong>注意</strong>：在定义角色全局变量时，应该将变量定义在playbook中，而不是在roles的defaults/main.yml文件中。因为在roles的defaults/main.yml文件中定义的变量是默认变量，不会被传递给其他角色或playbook。</p></blockquote><h2 id="magicvariables" tabindex="-1"><a class="header-anchor" href="#magicvariables" aria-hidden="true">#</a> MagicVariables</h2><ol><li><code>inventory_hostname</code>：当前主机在 Ansible inventory 中定义的名称</li><li><code>inventory_hostname_short</code>：当前主机在 Ansible inventory 中定义的名称的第一部分</li><li><code>hostvars</code>：包含当前所有主机及其变量的字典</li><li><code>group_names</code>：包含当前主机所属的所有组的列表</li><li><code>play_hosts</code>: 将执行当前任务的所有主机</li><li><code>ansible_host</code>: 指定主机的IP地址或域名，可以在Inventory中指定或者使用<code>add_host</code>模块动态添加。</li><li><code>ansible_port</code>: 指定SSH连接的端口，默认为22。</li><li><code>ansible_user</code>: 指定连接主机的用户名，默认为当前用户。</li><li><code>ansible_ssh_private_key_file</code>: 指定SSH连接使用的私钥文件路径。</li><li><code>ansible_connection</code>: 指定连接主机的方式，默认为SSH，还支持本地连接（local）、WinRM等方式。</li><li><code>ansible_python_interpreter</code>: 指定Python解释器的路径。</li><li><code>ansible_distribution</code>: 操作系统的发行版，如Ubuntu、CentOS等。</li><li><code>ansible_distribution_version</code>: 操作系统的版本号，如18.04、7.6等。</li><li><code>ansible_facts</code>: 存储主机的各种信息，比如操作系统版本、IP地址等。详细的信息可以使用命令 <code>ansible 127.0.0.1 -m setup</code>查看。</li></ol><blockquote><p>在 playbook 中使用 主机的变量，有以下几种方式：</p></blockquote><ol><li>引用主机变量：可以使用 <code>hostvars</code> 关键字来引用主机变量，格式为 <code>hostvars[&#39;主机名&#39;][&#39;变量名&#39;]</code>，例如：</li></ol><p><code>inventory.ini</code></p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token comment">; hosts 组应包含所有安装 greatdb 的主机 IP</span>
<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">hosts</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">172.17.140.22 ansible_connection</span><span class="token punctuation">=</span><span class="token value attr-value">ssh  ansible_ssh_user=admin  manage_user=admin  root_dir=/admin</span> 
<span class="token key attr-name">172.17.140.101 ansible_connection</span><span class="token punctuation">=</span><span class="token value attr-value">ssh  ansible_ssh_user=admin  manage_user=admin  root_dir=/admin</span> 

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">binlog_servers:children</span><span class="token punctuation">]</span></span>
masters
slaves

<span class="token comment">; define masters</span>
<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">masters</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">bing_server1 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">172.17.140.22 port=3326</span> 

<span class="token comment">; define slaves</span>
<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">slaves</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">bing_server2 ansible_host</span><span class="token punctuation">=</span><span class="token value attr-value">172.17.140.101 port=3326</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出主机组masters中第一个主机的信息</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> change slave binlog server to master
  <span class="token key atrule">debug</span><span class="token punctuation">:</span>
    <span class="token key atrule">msg</span><span class="token punctuation">:</span> <span class="token string">&quot;master_host=&#39;{{hostvars[master_binlog_server].ansible_host}}&#39;,master_port={{hostvars[master_binlog_server].port}}&quot;</span>
  <span class="token key atrule">vars</span><span class="token punctuation">:</span>
    <span class="token key atrule">master_binlog_server</span><span class="token punctuation">:</span> <span class="token string">&quot;{{ groups[&#39;masters&#39;][0] }}&quot;</span>
  <span class="token key atrule">no_log</span><span class="token punctuation">:</span> <span class="token boolean important">true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>循环输出主机组masters中所有主机的信息</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> upload backup file to slave sqlnodes
  <span class="token key atrule">debug</span><span class="token punctuation">:</span>
    <span class="token key atrule">cmd</span><span class="token punctuation">:</span> <span class="token string">&quot;master_host=&#39;{{hostvars[item].ansible_host}}&#39;,master_port={{hostvars[item].port}}&quot;</span>
  <span class="token key atrule">with_items</span><span class="token punctuation">:</span> <span class="token string">&quot;{{ groups[&#39;masters&#39;] }}&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>使用 <code>ansible_*</code> 系列变量：在 playbook 中可以使用 <code>ansible_*</code> 系列变量，这些变量是由 Ansible 自动设置的，比如：</li></ol><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Example playbook
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Print Ansible facts
      <span class="token key atrule">debug</span><span class="token punctuation">:</span>
        <span class="token key atrule">var</span><span class="token punctuation">:</span> ansible_distribution
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里的 <code>ansible_distribution</code> 就是一个 Ansible 内置变量，表示当前系统的发行版。</p><ol start="3"><li>使用 <code>lookup()</code> 函数：在 playbook 中可以使用<code>lookup(&#39;env&#39;)</code>和<code>lookup(&#39;ini&#39;)</code>分别获取主机的环境变量和inventory中定义的变量。</li></ol><p>假设目标主机的环境变量 <code>MY_ENV_VAR</code> 的值为 <code>my_value</code>，可以在 playbook 中使用以下方式来获取该环境变量的值：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Example playbook
  <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> Print variable using lookup
      <span class="token key atrule">debug</span><span class="token punctuation">:</span>
        <span class="token key atrule">var</span><span class="token punctuation">:</span> lookup(&#39;env&#39;<span class="token punctuation">,</span> &#39;MY_ENV_VAR&#39;)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>比如，假设我们在inventory文件中定义了一个名为webserver的组，并且为这个组中的主机定义了一个变量<code>http_port=80</code>，那么我们可以在playbook中使用lookup(‘ini’)来获取这个变量：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">-</span> <span class="token key atrule">hosts</span><span class="token punctuation">:</span> webserver
  <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">debug</span><span class="token punctuation">:</span>
        <span class="token key atrule">var</span><span class="token punctuation">:</span> lookup(&#39;ini&#39;<span class="token punctuation">,</span> &#39;http_port type=host group=webserver file=/path/to/inventory.ini&#39;)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这里，我们使用了lookup(‘ini’)函数，并指定了以下参数：</p><ul><li><code>type=host</code>：表示我们要获取主机级别的变量，而不是组级别或全局级别的变量。</li><li><code>group=webserver</code>：表示我们要获取webserver组中的主机的变量。</li><li><code>file=/path/to/inventory.ini</code>：表示我们的inventory文件的路径。</li></ul><p>通过这个lookup函数，我们可以获取到webserver组中所有主机的http_port变量的值。</p><h2 id="注册变量" tabindex="-1"><a class="header-anchor" href="#注册变量" aria-hidden="true">#</a> 注册变量</h2><p>注册变量，其实就是将操作结果，包括标准输出和标准错误输出，保存到变量中，然后再根据这个变量的内容来决定下一步的操作，在这个过程中用来保存操作结果的变量就叫注册变量。</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">---</span>
 <span class="token punctuation">-</span> <span class="token key atrule">hosts</span><span class="token punctuation">:</span> all
   <span class="token key atrule">remote_user</span><span class="token punctuation">:</span> root
   <span class="token key atrule">gather_facts</span><span class="token punctuation">:</span> no
   <span class="token key atrule">tasks</span><span class="token punctuation">:</span>
     <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> test the register variables
       <span class="token key atrule">shell</span><span class="token punctuation">:</span> uptime
       <span class="token key atrule">register</span><span class="token punctuation">:</span> results     <span class="token comment"># 使用关键字register声明注册变量，上面uptime命令产生的结果，存入到results中。结果是字典形式。</span>
 
     <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> print the register result
       <span class="token key atrule">debug</span><span class="token punctuation">:</span> msg=&quot;<span class="token punctuation">{</span><span class="token punctuation">{</span> results.stdout <span class="token punctuation">}</span><span class="token punctuation">}</span>&quot;   <span class="token comment"># 使用debug模块，打印出上面命令的输出结果。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的playbook执行结果如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ ansible-playbook test.yml
 
PLAY <span class="token punctuation">[</span>all<span class="token punctuation">]</span> ********************************************************************
 
TASK: <span class="token punctuation">[</span>test the register variables<span class="token punctuation">]</span> *******************************************
changed: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.212<span class="token punctuation">]</span>
changed: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.200<span class="token punctuation">]</span>
changed: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.162<span class="token punctuation">]</span>
 
TASK: <span class="token punctuation">[</span>print the register result<span class="token punctuation">]</span> *********************************************
ok: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.212<span class="token punctuation">]</span> <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token string">&quot;msg&quot;</span><span class="token builtin class-name">:</span> <span class="token string">&quot; 00:18:01 up 3 days,  2:56,  3 users,  load average: 0.02, 0.03, 0.05&quot;</span>          <span class="token comment">#msg的结果就是注册变量的标准输出</span>
<span class="token punctuation">}</span>
ok: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.200<span class="token punctuation">]</span> <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token string">&quot;msg&quot;</span><span class="token builtin class-name">:</span> <span class="token string">&quot; 00:18:04 up 4 days,  7:45,  3 users,  load average: 0.03, 0.06, 0.05&quot;</span>
<span class="token punctuation">}</span>
ok: <span class="token punctuation">[</span><span class="token number">10.0</span>.102.162<span class="token punctuation">]</span> <span class="token operator">=</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token string">&quot;msg&quot;</span><span class="token builtin class-name">:</span> <span class="token string">&quot; 00:18:04 up 4 days,  7:45,  3 users,  load average: 0.01, 0.02, 0.05&quot;</span>
<span class="token punctuation">}</span>
 
PLAY RECAP ********************************************************************
<span class="token number">10.0</span>.102.162               <span class="token builtin class-name">:</span> <span class="token assign-left variable">ok</span><span class="token operator">=</span><span class="token number">2</span>    <span class="token assign-left variable">changed</span><span class="token operator">=</span><span class="token number">1</span>    <span class="token assign-left variable">unreachable</span><span class="token operator">=</span><span class="token number">0</span>    <span class="token assign-left variable">failed</span><span class="token operator">=</span><span class="token number">0</span>
<span class="token number">10.0</span>.102.200               <span class="token builtin class-name">:</span> <span class="token assign-left variable">ok</span><span class="token operator">=</span><span class="token number">2</span>    <span class="token assign-left variable">changed</span><span class="token operator">=</span><span class="token number">1</span>    <span class="token assign-left variable">unreachable</span><span class="token operator">=</span><span class="token number">0</span>    <span class="token assign-left variable">failed</span><span class="token operator">=</span><span class="token number">0</span>
<span class="token number">10.0</span>.102.212               <span class="token builtin class-name">:</span> <span class="token assign-left variable">ok</span><span class="token operator">=</span><span class="token number">2</span>    <span class="token assign-left variable">changed</span><span class="token operator">=</span><span class="token number">1</span>    <span class="token assign-left variable">unreachable</span><span class="token operator">=</span><span class="token number">0</span>    <span class="token assign-left variable">failed</span><span class="token operator">=</span><span class="token number">0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>一个注册变量通常会有以下4个属性：</p><ul><li><code>changed</code>：任务是否对远程主机造成的变更。</li><li><code>delta</code>：任务运行所用的时间。</li><li><code>stdout</code>：正常的输出信息。</li><li><code>stderr</code>：错误信息。</li></ul>`,77),p=[t];function o(i,c){return n(),a("div",null,p)}const d=s(l,[["render",o],["__file","Ansible变量.html.vue"]]);export{d as default};
